class Solution {
    public int wordCount(String[] startWords, String[] targetWords) {
        int count = 0;
        for (String target : targetWords) {
            boolean found = false;
            for (String start : startWords) {
                if (canTransform(start, target)) {
                    found = true;
                    break;
                }
            }
            if (found) count++;
        }
        return count;
    }

    private boolean canTransform(String start, String target) {
        if (start.length() + 1 != target.length()) return false;
        int[] startCount = new int[26];
        int[] targetCount = new int[26];
        for (char c : start.toCharArray()) startCount[c - 'a']++;
        for (char c : target.toCharArray()) targetCount[c - 'a']++;
        for (int i = 0; i < 26; i++) {
            if (targetCount[i] > startCount[i] + 1 || (targetCount[i] > 0 && startCount[i] == 0 && targetCount[i] > 1)) return false;
        }
        return true;
    }
}
